from flask import Flask, redirect, request, session
from authlib.integrations.flask_client import OAuth
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

oauth = OAuth(app)
oauth.register(
    name='provider',
    client_id='your_client_id',
    client_secret='your_client_secret',
    authorize_url='provider_authorize_url',
    access_token_url='provider_token_url',
    userinfo_url='provider_userinfo_url',
    client_kwargs={'scope': 'openid profile email'}
)

@app.route('/login')
def login():
    redirect_uri = 'http://your_callback_url'
    return oauth.provider.authorize_redirect(redirect_uri)

@app.route('/callback')
def callback():
    token = oauth.provider.authorize_access_token()
    user_info = oauth.provider.parse_id_token(token)
    session['user_info'] = user_info
    return redirect('/profile')

@app.route('/profile')
def profile():
    user_info = session.get('user_info')
    if user_info:
        return f"User Info: {user_info}"
    else:
        return "User not authenticated"

if __name__ == '__main__':
    app.run()